#define fp float
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x) + (A.y)*(B.y) + (A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void
kernel_gpu_opencl(par_str par,
                  dim_str dim,
                  __global box_str* box,
                  __global FOUR_VECTOR* rv,
                  __global fp* qv,
                  __global FOUR_VECTOR* fv)
{
	int tx = (int)get_local_id(0);
	int l = (int)get_group_id(0);

	if (l >= (int)dim.number_boxes || tx >= NUMBER_PAR_PER_BOX) {
		return;
	}

	fp alpha = par.alpha;
	fp a2 = (fp)2.0f * alpha * alpha;

	long first_i = box[l].offset;
	long idxA = first_i + (long)tx;

	FOUR_VECTOR rA = rv[idxA];
	FOUR_VECTOR fA = fv[idxA];

	for (int k = 0; k < (1 + box[l].nn); k++) {
		int pointer;
		if (k == 0) {
			pointer = l;
		} else {
			pointer = box[l].nei[k - 1].number;
		}

		long first_j = box[pointer].offset;

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
			long idxB = first_j + (long)j;
			FOUR_VECTOR rB = rv[idxB];
			fp qB = qv[idxB];

			fp r2 = rA.v + rB.v - DOT(rA, rB);
			fp u2 = a2 * r2;
			fp vij = exp(-u2);
			fp fs = (fp)2.0f * vij;

			THREE_VECTOR d;
			d.x = rA.x - rB.x;
			d.y = rA.y - rB.y;
			d.z = rA.z - rB.z;

			fp fxij = fs * d.x;
			fp fyij = fs * d.y;
			fp fzij = fs * d.z;

			fA.v += qB * vij;
			fA.x += qB * fxij;
			fA.y += qB * fyij;
			fA.z += qB * fzij;
		}
	}

	fv[idxA] = fA;
}
